#import "WBHomeVappFeatureView.h"

@interface WBHomeVappFeatureView ()

@property(nonatomic, strong) NSString *iconName;
@property(nonatomic, strong) NSString *title;
@property(nonatomic, strong) NSString *describe;
@property(nonatomic, strong) UIImageView *iconImageView;
@property(nonatomic, strong) UILabel *titleLabel;
@property(nonatomic, strong) UILabel *describeLabel;

@end

@implementation WBHomeVappFeatureView

- (instancetype)initWithIcon:(NSString *)iconName title:(NSString *)title describe:(NSString *)describe featureType:(WBHomeVappFeatureType)type isStaticIcon:(BOOL)isStatic {
    if (self = [super init]) {
        self.iconName = iconName;
        self.title = title;
        self.describe = describe;
        self.featureType = type;
        self.isStaticIcon = isStatic;

        [self setUpUI];
    }
    return self;
}


#pragma mark - setUpUI

- (void)setUpUI {
    self.backgroundColor = [UIColor whiteColor];
    self.layer.cornerRadius = ZOOM(12);
    [self addAllSubviews];
    [self addAllConstraints];
    if (_featureType == WBHomeVappFeatureTypeMoreFunctions && self.isStaticIcon) {
        self.userInteractionEnabled = YES; // 启用交互
        UITapGestureRecognizer *tap = [[UITapGestureRecognizer alloc]
                                        initWithTarget:self
                                        action:@selector(moreFunctionsIconTapped)];
        [self addGestureRecognizer:tap];
    }
}

- (void)addAllSubviews {
    [self addSubview:self.iconImageView];
    [self addSubview:self.titleLabel];
    [self addSubview:self.describeLabel];
    if (self.featureType == WBHomeVappFeatureTypeMoreFunctions && self.isStaticIcon) {
        [self addSubview:self.staticImageView];
    } else {
        [self addSubview:self.switchButton];
    }
    [self addSubview:self.seperatorLine];
}

- (void)addAllConstraints {
    [_iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self).offset(ZOOM(8));
        make.centerY.equalTo(self);
        make.width.height.mas_equalTo(ZOOM(28));
    }];

    [_titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.iconImageView.mas_right).offset(ZOOM(6));
        make.top.equalTo(self.iconImageView).offset(ZOOM(-7));
    }];

    [_describeLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.titleLabel);
        make.top.equalTo(self.titleLabel.mas_bottom).offset(ZOOM(4));
    }];

    if (self.featureType == WBHomeVappFeatureTypeMoreFunctions && self.isStaticIcon) {
        [_staticImageView mas_makeConstraints:^(MASConstraintMaker *make) {
            make.right.equalTo(self).offset(-ZOOM(8));
            make.centerY.equalTo(self);
            make.width.height.mas_equalTo(ZOOM(18));
        }];
    } else {
        [_switchButton mas_makeConstraints:^(MASConstraintMaker *make) {
            make.right.equalTo(self);
            make.centerY.equalTo(self);
        }];
    }

    [_seperatorLine mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.bottom.equalTo(self);
        make.width.mas_equalTo(ZOOM(160));
        make.height.mas_equalTo(ZOOM(0.5));
    }];
}


#pragma mark - Events

- (void)moreFunctionsIconTapped {
    // 触发代理回调，传递点击事件
    if ([self.delegate respondsToSelector:@selector(featureView:didToggleType:)]) {
        [self.delegate featureView:self didToggleType:WBHomeVappFeatureTypeMoreFunctions];
    }
}


#pragma mark - lazy load

- (UIImageView *)iconImageView {
    if (!_iconImageView) {
        _iconImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:self.iconName]];
        _iconImageView.layer.cornerRadius = ZOOM(6);
        _iconImageView.layer.masksToBounds = YES;
    }
    return _iconImageView;
}

- (UILabel *)titleLabel {
    if (!_titleLabel) {
        _titleLabel = [[UILabel alloc] init];
        _titleLabel.text = self.title;
        _titleLabel.textColor = RGB(51, 51, 51);
        _titleLabel.font = WBPrimaryBoldFont(14);
    }
    return _titleLabel;
}

- (UILabel *)describeLabel {
    if (!_describeLabel) {
        _describeLabel = [[UILabel alloc] init];
        _describeLabel.text = self.describe;
        _describeLabel.textColor = RGB(102, 102, 102);
        _describeLabel.font = WBPrimaryFont(12);
    }
    return _describeLabel;
}

- (UISwitch *)switchButton {
    if (!_switchButton) {
        _switchButton = [[UISwitch alloc] init];
        _switchButton.transform = CGAffineTransformMakeScale(0.6, 0.6);
        [_switchButton addTarget:self action:@selector(switchValueChanged:) forControlEvents:UIControlEventValueChanged];
    }
    return _switchButton;
}

- (UIImageView *)staticImageView {
    if (!_staticImageView) {
        _staticImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"前往"]];
        _staticImageView.contentMode = UIViewContentModeScaleAspectFit;
        _staticImageView.userInteractionEnabled = NO;
    }
    return _staticImageView;
}

- (UIView *)seperatorLine {
    if (!_seperatorLine) {
        _seperatorLine = [[UIView alloc] init];
        _seperatorLine.backgroundColor = WBColorHex(0xE6E6E6);
    }
    return _seperatorLine;
}


#pragma mark - delegate

- (void)switchValueChanged:(UISwitch *)sender {
    // 通过代理通知控制器
    if ([self.delegate respondsToSelector:@selector(featureView:didToggleType:)]) {
        [self.delegate featureView:self didToggleType:self.featureType];
    }
}

- (void)setCompact:(BOOL)compact {
    _compact = compact;
    self.describeLabel.hidden = compact;
    [self.titleLabel mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.iconImageView.mas_right).offset(ZOOM(6));
        if (compact) {
            make.centerY.equalTo(self.iconImageView);
        } else {
            make.top.equalTo(self.iconImageView).offset(ZOOM(-7));
        }
    }];
}

- (void)setCornerStyle:(WBHomeVappFeatureCornerStyle)cornerStyle {
    _cornerStyle = cornerStyle;
    CGFloat r = ZOOM(12);
    if (@available(iOS 11.0, *)) {
        switch (cornerStyle) {
            case WBHomeVappFeatureCornerStyleAll:
                self.layer.cornerRadius = r;
                self.layer.maskedCorners = kCALayerMinXMinYCorner | kCALayerMaxXMinYCorner | kCALayerMinXMaxYCorner | kCALayerMaxXMaxYCorner;
                break;
            case WBHomeVappFeatureCornerStyleTop:
                self.layer.cornerRadius = r;
                self.layer.maskedCorners = kCALayerMinXMinYCorner | kCALayerMaxXMinYCorner;
                break;
            case WBHomeVappFeatureCornerStyleMiddle:
                self.layer.cornerRadius = 0;
                self.layer.maskedCorners = 0;
                break;
            case WBHomeVappFeatureCornerStyleBottom:
                self.layer.cornerRadius = r;
                self.layer.maskedCorners = kCALayerMinXMaxYCorner | kCALayerMaxXMaxYCorner;
                break;
        }
    } else {
        self.layer.cornerRadius = (cornerStyle == WBHomeVappFeatureCornerStyleMiddle) ? 0 : r;
    }
}


@end

