- (void)cleanCache {
    WBVAppUserInfo *userInfo = self.userInfo;
    BOOL couldClearCache = false;
    // cache cache with switch-case full through, non break
    switch (self.status) {
        case WBVappStatusWaitingDownload:
        case WBVappStatusDownloading:
        case WBVappStatusDownloaded:
        case WBVappStatusWaitingInstall:
        case WBVappStatusInstalling:
        case WBVappStatusResourceWaitingDownload:
        case WBVappStatusResourceDownloading:
        case WBVappStatusResourceDownloaded:
        case WBVappStatusResourceInstalling:
            break;// 以上几种情况都是不能删除安装、资源包的情况
        default:
        {
            couldClearCache = true;
            break;
        }
    }
    if(couldClearCache){
        [self removeCacheFileOrDirIfExist:userInfo.ipaZipPath];
        [self removeCacheFileOrDirIfExist:userInfo.resZipPath];
        [self removeCacheFileOrDirIfExist:userInfo.ipaUnzipPath];
        [self removeCacheFileOrDirIfExist:userInfo.resUnzipPath];
