        _session = [NSURLSession sessionWithConfiguration:NSURLSessionConfiguration.defaultSessionConfiguration delegate:self delegateQueue:[NSOperationQueue mainQueue]];
    }
    return self;
}

- (BOOL)isDownloading {
    if (_downloadTask && _downloadingVApp) {
        return TRUE;
    }
    return FALSE;
}


- (void)onEnterBackground {
    // if background mode's not enabled and the task's resumable, then save the task
}

- (void)onAppWillTerminate {
    if ([self isDownloading]) {
        // try to save the task
        [_downloadTask cancelByProducingResumeData:^(NSData * _Nullable resumeData) {
            if (resumeData == nil) {
                NSLog(@"Download: enter bg, unable to produce resumable data");
                [self.downloadingVApp setInMemoryStatus:WBVappStatusDownloadError];
                [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                             errorDomain:NSURLErrorDomain
                                               errorCode:-3006  // NSURLErrorDownloadDecodingFailedMidStream
                                            errorMessage:@"Resume data generation failed: download decoding interrupted"
                                                 forVApp:self.downloadingVApp];
                self.downloadingVApp.progress = 0.0;
            } else {
                [WBStorageManager.sharedManager saveResumableData:resumeData forURL:self.downloadingVApp.versionInfo.ipaURL];
                NSLog(@"Download: enter bg, save resume data");
                [self.downloadingVApp setInMemoryStatus:WBVappStatusDownloadInterrupted];
            }
        }];
    }
}

- (void)doTimelyCheck {
    dispatch_after(dispatch_time_delay(1.0), dispatch_get_main_queue(), ^{
        [self checkDownloadQueue];
    });
}



- (void)checkDownloadQueue {
    if (_downloadTask == nil) {
        if ([_downloadQueue count] > 0) {
            _downloadingVApp = _downloadQueue.firstObject;
            switch(_downloadingVApp.status) {
                case WBVappStatusWaitingDownload:
                    self.downloadTask = [_session downloadTaskWithURL:[NSURL URLWithString:_downloadingVApp.versionInfo.ipaURL]];
                    [self.downloadTask resume];
                    _downloadStartTime = CFAbsoluteTimeGetCurrent();
                    [_downloadingVApp setInMemoryStatus: WBVappStatusDownloading];
                    break;
                case WBVappStatusDownloadError:
                    PostNotificationOnMainThread(WBVAppDownloadErrorNotification, _downloadingVApp);
                    [_downloadQueue popFirstObject];
                    break;
                case WBVappStatusDownloaded:
                    [_downloadQueue popFirstObject];
                    [WBVAppManager.sharedManager installVApp:_downloadingVApp];
                    break;
                case WBVappStatusDownloadInterrupted:
                    if (UIApplication.sharedApplication.applicationState == UIApplicationStateActive) {
                        NSData *resumeData = [WBStorageManager.sharedManager loadResumableDataForURL:_downloadingVApp.versionInfo.ipaURL];
                        if (resumeData) {
                            if (_downloadStartTime == 0) {
                                _downloadStartTime = CFAbsoluteTimeGetCurrent();
                            }
                            self.downloadTask = [_session downloadTaskWithResumeData:resumeData];
                            [self.downloadTask resume];
                            NSLog(@"Download: resume");
                            [_downloadingVApp setInMemoryStatus: WBVappStatusDownloading];
                        } else {
                            PostNotificationOnMainThread(WBVAppDownloadErrorNotification, _downloadingVApp);
                            [_downloadQueue popFirstObject];
                        }
                    }
                    break;
                default:
                    break;
            }
        }
    }
    [self doTimelyCheck];
}


- (BOOL)addToDownloadQueue:(WBVAppModel *)vapp {
    if (vapp.status != WBVappStatusWaitingDownload) {
        return FALSE;
    }
    [_downloadQueue addObject:vapp];
    return TRUE;
}


#pragma mark - NSURLSessionDataDelegate

- (void)URLSession:(NSURLSession *)session downloadTask:(NSURLSessionDownloadTask *)downloadTask
      didWriteData:(int64_t)bytesWritten
 totalBytesWritten:(int64_t)totalBytesWritten
totalBytesExpectedToWrite:(int64_t)totalBytesExpectedToWrite {
    if (downloadTask != self.downloadTask) {
        return;
    }
    float newProgress = (CGFloat)totalBytesWritten/(CGFloat)totalBytesExpectedToWrite;
    if (fabs(newProgress - _downloadingVApp.progress) > 0.001) {
        _downloadingVApp.progress = newProgress;
        [_downloadingVApp setInMemoryStatus:WBVappStatusDownloading];
    }
}

- (void)URLSession:(NSURLSession *)session downloadTask:(NSURLSessionDownloadTask *)downloadTask didFinishDownloadingToURL:(NSURL *)location {
    if (downloadTask != self.downloadTask) {
        return;
    }
    NSHTTPURLResponse *resp = (NSHTTPURLResponse *)downloadTask.response;
    if (!(resp.statusCode >= 200 && resp.statusCode < 299)) {
        NSLog(@"Download: unexpected download error: code %zd", resp.statusCode);
        [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                     errorDomain:@"HTTP"
                                      errorCode:resp.statusCode
                                   errorMessage:[NSString stringWithFormat:@"HTTP %zd: Server rejected download request", resp.statusCode]
                                       forVApp:self.downloadingVApp];
        return;
    }
    if (location == nil) {
        NSLog(@"Download: unknown download error occur");
        [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                     errorDomain:NSPOSIXErrorDomain
                                      errorCode:-3001   // NSURLErrorCannotOpenFile
                                   errorMessage:@"Downloaded file location is invalid or inaccessible"
                                       forVApp:self.downloadingVApp];
        return;
    }

    NSData *fileData = [NSData dataWithContentsOfURL:location];
    if ([[fileData sha1String] caseInsensitiveCompare:_downloadingVApp.versionInfo.ipaHash] == 0) {
        NSLog(@"Download: hash match");
        if ([WBStorageManager.sharedManager saveIPAForVapp:_downloadingVApp from:location]) {
            NSLog(@"Download: saved");
            [_downloadingVApp setInMemoryStatus:WBVappStatusDownloaded];
            CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
            NSInteger cost = (NSInteger)(now-_downloadStartTime);
            NSLog(@"Download: time cost %zd", cost);
            [WBEventManager logVappDownloadResultEvent:_downloadingVApp result:@"0" timeCost:cost];
            NSLog(@"Download: success");
            return;
        } else {
            NSLog(@"Download: save failed");
            [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                         errorDomain:NSPOSIXErrorDomain
                                           errorCode:-3004   // NSURLErrorCannotWriteToFile
                                        errorMessage:@"Failed to save IPA file to local storage"
                                             forVApp:self.downloadingVApp];
        }
    } else {
        NSLog(@"Download: hash error");
        [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                     errorDomain:WBErrorDomainSecurity
                                      errorCode:10002   // 自定义哈希不匹配错误码
                                   errorMessage:[NSString stringWithFormat:@"SHA1 mismatch: expected %@, got %@", _downloadingVApp.versionInfo.ipaHash, [fileData sha1String]]
                                       forVApp:self.downloadingVApp];
    }
    [_downloadingVApp setInMemoryStatus:WBVappStatusDownloadError];
}

- (void)URLSession:(NSURLSession *)session task:(NSURLSessionTask *)task didCompleteWithError:(NSError *)error {
    if (task != self.downloadTask) {
        return;
    }

    if (!error) {
        NSLog(@"Download: finished with no error, task ending");
        _downloadingVApp = nil;
        _downloadTask = nil;
    } else {
        if ([error.domain isEqualToString:NSURLErrorDomain]) {
            if (error.code == NSURLErrorNetworkConnectionLost) {
                NSLog(@"Download: error, connection lost");
                [_downloadTask cancelByProducingResumeData:^(NSData * _Nullable resumeData) {
                    if (resumeData == nil) {
                        NSLog(@"Download: interrupted, unable to produce resumable data");
                        [self.downloadingVApp setInMemoryStatus:WBVappStatusDownloadError];
                        [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                                     errorDomain:error.domain
                                                       errorCode:error.code
                                                    errorMessage:error.localizedDescription
                                                         forVApp:self.downloadingVApp];
                        self.downloadingVApp.progress = 0.0;
                        [WBEventManager logVappDownloadResultEvent:self.downloadingVApp result:error.localizedDescription timeCost:0];
                    } else {
                        [WBStorageManager.sharedManager saveResumableData:resumeData forURL:self.downloadingVApp.versionInfo.ipaURL];
                        NSLog(@"Download: interrupted, save resume data");
                        self.downloadTask = nil;
                        [self.downloadingVApp setInMemoryStatus:WBVappStatusDownloadInterrupted];
                    }
                }];
            } else if (error.code == NSURLErrorCancelled) {
                NSLog(@"Download: error, manually canceld");
                [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                             errorDomain:error.domain
                                               errorCode:error.code
                                            errorMessage:error.localizedDescription
                                                 forVApp:_downloadingVApp];
                [WBEventManager logVappDownloadResultEvent:_downloadingVApp result:error.localizedDescription timeCost:0];
            } else {
                NSLog(@"Download: error, unexpected");
                [_downloadingVApp setInMemoryStatus:WBVappStatusDownloadError];
                [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                             errorDomain:error.domain
                                              errorCode:error.code
                                           errorMessage:error.localizedDescription
                                               forVApp:_downloadingVApp];
            }
        } else {
            NSLog(@"Download: unexpected error occured..");
            [WBEventManager logVappDownloadResultEvent:_downloadingVApp result:error.localizedDescription timeCost:0];
            [_downloadingVApp setInMemoryStatus:WBVappStatusDownloadError];
            [[WBVAppManager sharedManager] saveError:WBVappStatusDownloadError
                                         errorDomain:error.domain
                                          errorCode:error.code
                                       errorMessage:error.localizedDescription
                                           forVApp:_downloadingVApp];
        }
    }
}

