- (void)updateCell {
    if ([_vapp literalStatus]) {
        self.vappNameLabel.text = [_vapp literalStatus];
    } else {
        self.vappNameLabel.text = [_vapp getDisplayName];
    }
    self.vappIconImageView.imageURL = [_vapp getDisplayIconURL];

    if ((_vapp.status & (WBVappStatusResourceWaitingDownload | WBVappStatusResourceDownloading | WBVappStatusResourceDownloaded | WBVappStatusResourceDownloadError | WBVappStatusResourceDownloadInterrupted | WBVappStatusResourceDownloadGiveUp | WBVappStatusResourceInstalling | WBVappStatusResourceInstalled | WBVappStatusResourceInstallError | WBVappStatusIniting)) || _vapp.status == WBVappStatusNone) {
        self.progressView.hidden = YES;
    } else {
        self.progressView.hidden = NO;
        if (_vapp.progress == 1.0f) {
            switch (_vapp.status) {
                case WBVappStatusDownloading:
                case WBVappStatusDownloaded:
                    self.progressView.progress = 0.999f;
                    break;
                default:
                    self.progressView.progress = _vapp.progress;
                    break;
            }
        } else if (_vapp.progress == 0.0f) {
            switch (_vapp.status) {
                case WBVappStatusWaitingDownload:
                case WBVappStatusDownloading:
                case WBVappStatusWaitingInstall:
                case WBVappStatusInstalling:
                    self.progressView.progress = 0.001f;
                    break;
                default:
                    self.progressView.progress = _vapp.progress;
                    break;
            }
        } else {
            self.progressView.progress = _vapp.progress;
        }
