- (void)updateSelectedFeaturesUI {
    for (UIView *selectedFeatureView in self.selectedFeatureViews) {
        [selectedFeatureView removeFromSuperview];
    }
    [self.selectedFeatureViews removeAllObjects];

    NSInteger count = self.selectedFeatureCodes.count;
    if (count <= 0) {
        self.hideFeaturesButton.hidden = YES;
        self.editFeaturesButton.hidden = YES;
        self.backgroundColor = [UIColor clearColor];
        self.vappBackView.backgroundColor = [UIColor clearColor];
        return;
    }

    self.hideFeaturesButton.hidden = NO;
    self.editFeaturesButton.hidden = NO;
    self.backgroundColor = RGB(246, 246, 246);
    self.vappBackView.backgroundColor = [UIColor whiteColor];

    CGFloat itemHeight = (count == 3) ? ZOOM(52) : ZOOM(78);
    WBHomeVappFeatureView *prev = nil;

    for (NSUInteger i = 0; i < count; i++) {
        NSString *code = self.selectedFeatureCodes[i];
        WBHomeVappFeatureView *view = [self featureViewForCode:code];
        view.compact = (count == 3);
        view.delegate = self.parentVC;
        if (count == 1) {
            view.cornerStyle = WBHomeVappFeatureCornerStyleTop;
        } else if (count == 2) {
            view.cornerStyle = (i == 0) ? WBHomeVappFeatureCornerStyleTop : WBHomeVappFeatureCornerStyleBottom;
        } else {
            view.cornerStyle = (i == 0) ? WBHomeVappFeatureCornerStyleTop : ((i == count - 1) ? WBHomeVappFeatureCornerStyleBottom : WBHomeVappFeatureCornerStyleMiddle);
        }
        [self.contentView addSubview:view];
        [self.selectedFeatureViews addObject:view];

        [view mas_makeConstraints:^(MASConstraintMaker *make) {
            make.left.equalTo(self.vappBackView.mas_right).offset(ZOOM(8));
            make.right.equalTo(self.contentView).offset(ZOOM(-8));
            make.height.mas_equalTo(itemHeight);
            if (prev) {
                make.top.equalTo(prev.mas_bottom);
            } else {
                make.top.equalTo(self.contentView).offset(ZOOM(8));
            }
        }];
        prev = view;
        view.seperatorLine.hidden = (i == count - 1);
        if (view.switchButton) {
            if ([code isEqualToString:@"notification"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isNotificationSwitchOn];
            } else if ([code isEqualToString:@"lock"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isLockSwitchOn];
            } else if ([code isEqualToString:@"disguise"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isDisguiseSwitchOn];
            } else if ([code isEqualToString:@"pretense"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isPretenseSwitchOn];
            } else if ([code isEqualToString:@"oneclick"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isOneClickSwitchOn];
            }
        }
    }

    if (count == 1) {
        WBHomeVappFeatureView *moreFunctionsView = [[WBHomeVappFeatureView alloc] initWithIcon:@"Home_moreFunctions_icon" title:@"更多功能" describe:@"点击查看更多功能" featureType:WBHomeVappFeatureTypeMoreFunctions isStaticIcon:YES];
        moreFunctionsView.compact = NO;
        moreFunctionsView.cornerStyle = WBHomeVappFeatureCornerStyleBottom;
        moreFunctionsView.seperatorLine.hidden = YES;
        moreFunctionsView.delegate = self.parentVC;
        [self.contentView addSubview:moreFunctionsView];
        [self.selectedFeatureViews addObject:moreFunctionsView];
        [moreFunctionsView mas_makeConstraints:^(MASConstraintMaker *make) {
            make.left.equalTo(self.vappBackView.mas_right).offset(ZOOM(8));
            make.top.equalTo(prev.mas_bottom);
            make.right.equalTo(self.contentView).offset(ZOOM(-8));
            make.height.mas_equalTo(ZOOM(78));
        }];
        prev = moreFunctionsView;
    }

    UIView *anchor = prev;
    [self.hideFeaturesButton mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.vappBackView.mas_right).offset(ZOOM(8));
        make.top.equalTo(anchor.mas_bottom).offset(ZOOM(8));
        make.width.mas_equalTo(ZOOM(99));
        make.height.mas_equalTo(ZOOM(36));
    }];
    [self.editFeaturesButton mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.hideFeaturesButton.mas_right).offset(ZOOM(8));
        make.top.equalTo(self.hideFeaturesButton);
        make.right.equalTo(self.contentView).offset(ZOOM(-8));
        make.height.mas_equalTo(ZOOM(36));
    }];
}

- (WBHomeVappFeatureView *)featureViewForCode:(NSString *)code {
    WBVIPFeatureModel *model = [self featureModelForCode:code];
    NSString *icon = model.icon_v3_svip ?: model.icon_v3_vip ?: model.icon_v2 ?: model.icon_v1 ?: model.icon_v0;
    NSString *title = model.name ?: @"";
    NSString *desc = [self descForCode:code];
    WBHomeVappFeatureType type = WBHomeVappFeatureTypeMoreFunctions;
    BOOL isStatic = YES;
    if ([code isEqualToString:@"notification"]) {
        type = WBHomeVappFeatureTypeNotifications;
        isStatic = NO;
    } else if ([code isEqualToString:@"lock"]) {
        type = WBHomeVappFeatureTypeLock;
    } else if ([code isEqualToString:@"disguise"]) {
        type = WBHomeVappFeatureTypeDisguise;
    } else if ([code isEqualToString:@"pretense"]) {
        type = WBHomeVappFeatureTypePretense;
    } else if ([code isEqualToString:@"oneclick"]) {
        type = WBHomeVappFeatureTypeOneclick;
    }

    WBHomeVappFeatureView *view = [[WBHomeVappFeatureView alloc] initWithIcon:icon title:title describe:desc featureType:type isStaticIcon:isStatic];
    if (view.switchButton) {
        if ([code isEqualToString:@"notification"]) {
            [view.switchButton setOn:_vapp.featureStatusInfo.isNotificationSwitchOn];
        } else if ([code isEqualToString:@"lock"]) {
            [view.switchButton setOn:_vapp.featureStatusInfo.isLockSwitchOn];
        } else if ([code isEqualToString:@"disguise"]) {
            [view.switchButton setOn:_vapp.featureStatusInfo.isDisguiseSwitchOn];
        } else if ([code isEqualToString:@"pretense"]) {
            [view.switchButton setOn:_vapp.featureStatusInfo.isPretenseSwitchOn];
        } else if ([code isEqualToString:@"oneclick"]) {
            [view.switchButton setOn:_vapp.featureStatusInfo.isOneClickSwitchOn];
        }
    }
    return view;
}

- (WBVIPFeatureModel *)featureModelForCode:(NSString *)code {
    NSArray<WBVIPFeatureModel*> *features = [WBVIPFeatureManager.sharedManager getFeatures];
    for (WBVIPFeatureModel *f in features) {
        if ([f.code_name isEqualToString:code]) return f;
    }
    return [WBVIPFeatureModel new];
}

- (NSString *)descForCode:(NSString *)code {
    if ([code isEqualToString:@"notification"]) return @"关键消息永不丢失";
    if ([code isEqualToString:@"lock"]) return @"专属密码保护隐私";
    if ([code isEqualToString:@"pretense"]) return @"一键切换“伪装界面”";
    if ([code isEqualToString:@"disguise"]) return @"更换应用名称和图标";
    if ([code isEqualToString:@"oneclick"]) return @"点桌面应用进入微信";
    return @"";
