#pragma mark - reserve action

/// Designated for reserving vapp.
/// - Parameters:
///   - isHard: Hard will ignore action request.
- (void)reserveVApp:(WBVAppModel *)vapp hard:(BOOL)isHard callback:(VAppActionCallback)callbackHandler {
    if (!isHard && !self.stashedReservingApp) { // Not hard reverse will send action request, stash this vapp, in case the action request returns an url which invokes to reserve current vapp by vappId in the params of url.
        self.stashedReservingApp = vapp;
    }
    self.stashedReservingApp = vapp;
    void (^defaultReserveAction)(void) = ^{
        [WBNetworkManager.defaultManager reserveVappWithVappId:vapp.vid callback:^(id  _Nullable json, NSError * _Nullable error) {
            if (error) {
                if (callbackHandler) callbackHandler(vapp, actionErrorFail);
            } else {
                vapp.reserveCount += 1;
                vapp.reserved = TRUE;
                if (callbackHandler) callbackHandler(vapp, actionErrorSuccess);
            }
        }];
    };
    if (isHard) return defaultReserveAction();
    [[WBActionRequestManager sharedManager] requestReserveVappWithVappId:vapp.vid defaultHandler:^(WBBaseActionModel * _Nullable actionModel) {
        defaultReserveAction();
    }];
}

/// Convenience
- (void)reserveVApp:(WBVAppModel *)vapp callback:(VAppActionCallback)callbackHandler {
    [self reserveVApp:vapp hard:false callback:callbackHandler];
}

/// Convenience
- (void)reserveVAppWithId:(NSInteger)vappId hard:(BOOL)isHard callback:(VAppActionCallback)callbackHandler {
    if (self.stashedReservingApp && self.stashedReservingApp.vid == vappId) {
        [self reserveVApp:self.stashedReservingApp hard:isHard callback:callbackHandler];
        self.stashedReservingApp = nil; // "Consume" the stashed vapp.
    } else {
        [self queryVAppWithId:vappId needsFlushLocalStorage:false next:^(WBVAppModel * _Nullable vapp, NSError * _Nullable error) {
            if (error) {
                if (callbackHandler) callbackHandler(nil, actionErrorFail);
                return;
            }
            [self reserveVApp:vapp hard:isHard callback:callbackHandler];
        }];
    }
}

