- (void)removeVApp:(WBVAppModel *)vapp callback:(VAppActionCallback)callbackHandler {
    [WBEventManager logVappDeleteEvent:vapp];
    // 如果没有清理，将信息记录下来
    if ([WBStorageManager.sharedManager hasIPA:vapp.bundleId ofSha1Hash:vapp.versionInfo.ipaHash]) {
        WBPackageInfo *current = [[WBPackageInfo alloc] init];
        current = [[WBPackageInfo alloc] initWithVAppModel:vapp];
        [self.deleteUncleanedAppPackages addObject:current];
        [self saveDeleteUncleanedAppPaths];
    }
    OAAErr errCode = oaa_remove_user(vapp.bundleId, vapp.versionInfo.version, vapp.userInfo.user);
    [WBEventManager logVappDeleteResultEvent:vapp result:@(errCode).stringValue];
    vapp.userInfo = nil;
    [_myApps removeObject:vapp];
    vapp.progress = 0.0;
    [self saveStatus:WBVappStatusNone forVApp:vapp];

    if (callbackHandler) callbackHandler(vapp, actionErrorSuccess);
}

- (void)downloadVApp:(WBVAppModel *)vapp {
    if ([WBStorageManager.sharedManager hasIPA:vapp.bundleId ofSha1Hash:vapp.versionInfo.ipaHash]) {
        [WBStorageManager.sharedManager saveIPARes:vapp];
        [self installVApp:vapp];
    } else {
        [self saveStatus:WBVappStatusWaitingDownload forVApp:vapp];
        [WBVAppDownloadManager.sharedManager addToDownloadQueue:vapp];
        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappDownloading defaultHandler:nil];
    }
}

