    [route name:@"vapp" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSAssert(userInfo[@"id"] != nil, @"url should contain a parameter 'id'");
        int vappId = [userInfo[@"id"] intValue];
        WBVAppModel *target = nil;
        for (WBVAppModel *app in WBVAppManager.sharedManager.myApps) {
            if (app.vid == vappId) { target = app; break; }
        }
        if (target) {
            self.settingVapp = target;
            if (self.settingVapp) {
                self.navigationItem.rightBarButtonItem = self.vappSwitchButtonItem;
            }
            [self initSettings];
            [self.tableView reloadData];
        }
        next(self);
    }];

    [route name:@"notification" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {

    }];

    [route name:@"clean" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [self onActionClearCache];
    }];
