- (void)jun_routeBuild:(JUNRouteBuilder *)route {
    [route name:@"vapp" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSAssert(userInfo[@"id"] != nil, @"url should contain a parameter 'id'");
        int vappId = [userInfo[@"id"] intValue];
        WBVAppModel *target = nil;
        for (WBVAppModel *app in WBVAppManager.sharedManager.myApps) {
            if (app.vid == vappId) { target = app; break; }
        }
        if (target) {
            self.settingVapp = target;
            if (self.settingVapp) {
                self.navigationItem.rightBarButtonItem = self.vappSwitchButtonItem;
            }
            [self initSettings];
            [self.tableView reloadData];
        }
        next(self);
    }];

    [route name:@"notification" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {

    }];

    [route name:@"clean" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [self onActionClearCache];
    }];
}

- (instancetype)init {
    if (self = [super init]) {
        self.hidesBottomBarWhenPushed = YES;
        if (!self.settingVapp && [WBVAppManager.sharedManager.myApps count]) {
            self.settingVapp = WBVAppManager.sharedManager.myApps[0];
        } else {
            self.settingVapp = nil;
        }
        [[NSNotificationCenter defaultCenter] addObserverForName:WBEnableSecurityLockNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            WBVAppModel *vapp = notification.object;
            WBSettingVappPasswordController *settingPasswordVC = [[WBSettingVappPasswordController alloc] initWithVapp:vapp];
            [self.navigationController pushViewController:settingPasswordVC animated:YES];
        }];
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    [self initSettings];
    self.title = @"设置";
    if (self.settingVapp) {
        self.navigationItem.rightBarButtonItem = self.vappSwitchButtonItem;
    }
    self.bannerAdHeight = ZOOM(75);
    self.maxNativeAdRetryCount = 3;
    self.nativeAdRetryInterval = 1.0;     // 初始重试间隔
    self.nativeAdRetryCount = 0;
}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [self updatePasswordDisplay];   // 动态更新密码显示
    [self didUpdateVappIcon];

    if ([WBSettingManager sharedManager].bannerAdEnableShow && ([WBSettingManager sharedManager].bannerAdPosition & WBAdsShowPositionSettingGlobalPage)) {
        [self groMoreBannerAdLoad];  // 加载 banner 广告
    }
    if ([WBSettingManager sharedManager].nativeAdEnableShow && ([WBSettingManager sharedManager].nativeAdPosition & WBAdsShowPositionSettingGlobalPage)) {
        [self groMoreNativeAdLoad]; // 加载信息流广告
    }
}

- (void)viewWillDisappear:(BOOL)animated {
    [super viewWillDisappear:animated];
    [self closeAd];
}

- (void)dealloc {
    if (self.nativeAdRetryTimer) {
        [self.nativeAdRetryTimer invalidate];
        self.nativeAdRetryTimer = nil;
    }
}

- (void)closeAd {
    for (BUNativeAd *nativeAd in self.nativeAdDataArray) {
        if (nativeAd.mediation.canvasView) {
            [nativeAd.mediation.canvasView removeFromSuperview];
        }
    }
    self.nativeAdDataArray = nil;
    if (self.nativeAdManager) {
        [self.nativeAdManager.mediation destory];
        self.nativeAdManager = nil;
    }
    [self.bannerAdView removeFromSuperview];
    self.bannerAdView = nil;
}

- (void)updatePasswordDisplay {
    NSString *passwordString = [self getCurrentPasswordString];

    // 更新密码单元格显示
    NSIndexPath *passwordIndexPath = [NSIndexPath indexPathForRow:0 inSection:0];
    UITableViewCell *passwordCell = [self.tableView cellForRowAtIndexPath:passwordIndexPath];

    if ([passwordCell isKindOfClass:[WBSettingNormalDetailCell class]]) {
        WBSettingNormalDetailCell *normalCell = (WBSettingNormalDetailCell *)passwordCell;
        normalCell.detailTextLabel.text = passwordString;
    }
}

- (NSString *)getCurrentPasswordString {
    NSString *currentPassword = WBAppManager.sharedManager.globalPassword;
    if ([currentPassword isEqualToString:@"1234"]) {
        return @"初始密码：1234";
    } else {
        return @"";
    }
}


