- (void)initSettings {
    NSMutableArray *sections = [NSMutableArray array];
    if (!WBSettingManager.sharedManager.HideVIPPrivilege && (WBSettingManager.sharedManager.IsVIP || WBSettingManager.sharedManager.IsSVIP)) {
        [sections addObject:[self getPasswordSection]];
    }
    _utilitySectionIndex = sections.count;
    [sections addObject:[self getUtilitySection:self.settingVapp]];
    [sections addObject:[self getGuidanceFeatureSection]];

    self.factory = [[WBTableViewSettingFactory alloc] initWithSections:sections];
}

