static NSNumber *WBNonNegativeNumber(id obj) {
    if (!obj || obj == [NSNull null]) return nil;
    NSInteger value = 0;
    if ([obj isKindOfClass:NSNumber.class]) {
        value = [((NSNumber *)obj) integerValue];
    } else {
        value = [[obj description] integerValue];
    }
    if (value < 0) value = 0;
    return @(value);
}

static NSString *WBStringFromObj(id obj) {
    if (!obj || obj == [NSNull null]) return nil;
    NSString *stringValue = nil;
    if ([obj isKindOfClass:NSString.class]) {
        stringValue = (NSString *)obj;
    } else if ([obj respondsToSelector:@selector(stringValue)]) {
        stringValue = [obj stringValue];
    } else {
        stringValue = [obj description];
    }
    if (stringValue.length <= 0) return nil;
    return stringValue;
}

static NSNumber *WBApplyGrantValue(NSNumber *currentValue, NSString *op, NSNumber *amountValue) {
