    NSInteger amount = [amountValue integerValue];
    if (current < 0) current = 0;
    if (amount < 0) amount = 0;
    NSString *normalizedOp = [[op ?: @"" lowercaseString] copy];
    if ([normalizedOp isEqualToString:@"topup"]) {
        return @(current + amount);
    }
    if ([normalizedOp isEqualToString:@"set"]) {
        return @(amount);
    }
    if ([normalizedOp isEqualToString:@"cap"]) {
        return @(MAX(current, amount));
    }
    return nil;
}

@implementation WBBenefitManager

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBBenefitManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        self.currentBenefit = WBSettingManager.sharedManager.Benefit;
        self.currentBenefitSupport = WBSettingManager.sharedManager.BenefitSupport;
        [NSNotificationCenter.defaultCenter addObserverForName:WBAccountStatusChangedNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull note) {
            self.currentBenefit = WBSettingManager.sharedManager.Benefit;
            self.currentBenefitSupport = WBSettingManager.sharedManager.BenefitSupport;
        }];
    }
    return self;
}

+ (NSDictionary<NSString *, NSNumber *> *)normalizedTrialUsage:(NSDictionary<NSString *, NSNumber *> *)existing features:(NSArray *)features {
    NSMutableSet *allowed = [NSMutableSet set];
    for (id obj in features) {
        if ([obj respondsToSelector:@selector(bit)]) {
            NSNumber *bitNum = [obj valueForKey:@"bit"];
            NSInteger bit = [bitNum integerValue];
            if (bit != 0) {
                [allowed addObject:[NSString stringWithFormat:@"%ld", (long)bit]];
            }
        }
    }
    NSMutableDictionary *result = [NSMutableDictionary dictionaryWithCapacity:allowed.count];
    [existing enumerateKeysAndObjectsUsingBlock:^(id key, id obj, BOOL *stop) {
        if ([allowed containsObject:key]) {
            NSInteger integerValue = 0;
            if ([obj isKindOfClass:NSNumber.class]) {
                integerValue = [obj integerValue];
            } else {
                integerValue = [[obj description] integerValue];
            }
            if (integerValue < 0) integerValue = 0;
            result[key] = @(integerValue);
        }
    }];
    for (NSString *key in allowed) {
        if (!result[key]) result[key] = @(0);
    }
    return result;
}

+ (void)syncTrialUsageWithProperties:(id)json features:(NSArray *)features {
    NSDictionary *existing = WBSettingManager.sharedManager.BenefitTrialUsageTimes ?: @{};
    NSMutableDictionary *updated = [existing mutableCopy];
    if (!updated) updated = [NSMutableDictionary dictionary];
    NSArray<NSString *> *appliedGrantIds = WBSettingManager.sharedManager.BenefitTrialAppliedGrantIds ?: @[];
    NSMutableSet<NSString *> *appliedGrantIdSet = [NSMutableSet setWithArray:appliedGrantIds];
    BOOL appliedGrantIdChanged = NO;
    if ([json isKindOfClass:NSArray.class]) {
        for (NSDictionary *dict in (NSArray *)json) {
            NSNumber *bitNum = WBNonNegativeNumber(dict[@"benefitBit"]);
            if (!bitNum || [bitNum integerValue] == 0) continue;
            NSString *key = WBStringFromObj(bitNum);
            if (key.length <= 0) continue;

            NSDictionary *grant = [dict[@"grant"] isKindOfClass:NSDictionary.class] ? dict[@"grant"] : nil;
            NSString *grantId = WBStringFromObj(grant[@"grantId"]);
            NSString *op = WBStringFromObj(grant[@"op"]);
            NSNumber *amountNum = WBNonNegativeNumber(grant[@"amount"]);
            if (grantId.length > 0 && op.length > 0 && amountNum) {
                if (![appliedGrantIdSet containsObject:grantId]) {
                    NSNumber *currentNum = WBNonNegativeNumber(updated[key]) ?: @(0);
                    NSNumber *newValue = WBApplyGrantValue(currentNum, op, amountNum);
                    if (newValue) {
                        updated[key] = newValue;
                        [appliedGrantIdSet addObject:grantId];
                        appliedGrantIdChanged = YES;
                    }
                }
                continue;
            }

            NSNumber *timesNum = WBNonNegativeNumber(dict[@"trialTimes"]);
            if (timesNum && !updated[key]) {
                updated[key] = timesNum;
            }
        }
    }
    NSDictionary *merged = [self normalizedTrialUsage:updated features:features];
    WBSettingManager.sharedManager.BenefitTrialUsageTimes = merged;
    if (appliedGrantIdChanged) {
        WBSettingManager.sharedManager.BenefitTrialAppliedGrantIds = appliedGrantIdSet.allObjects;
    }
}

- (BOOL)isBenefitAvailable:(WBUserBenefit)bit {
    WBSettingManager *manager = WBSettingManager.sharedManager;
    if ((manager.BenefitSupport & bit) == 0) return NO;
    if ((manager.Benefit & bit) != 0) return YES;
    if (manager.BenefitTrialProperties.count <= 0) return NO;
    for (id obj in manager.BenefitTrialProperties) {
        if (![obj isKindOfClass:NSDictionary.class]) continue;
        NSDictionary *dict = (NSDictionary *)obj;
        if ([dict[@"benefitBit"] integerValue] != bit) continue;

        id trialTimesObj = dict[@"trialTimes"];
        if (trialTimesObj && trialTimesObj != [NSNull null]) {
            return [manager trialUsageTimesForBenefitBit:bit] > 0;
        }

        id descObj = dict[@"desc"];
        return descObj && descObj != [NSNull null] && [[descObj description] length] > 0;
    }
    return NO;
}


#pragma mark - handle switch benefit function

- (BOOL)handleSwitchBenefitFunction:(WBUserBenefit)function target:(BOOL)target vapp:(WBVAppModel *)vapp {
    WBUserBenefitFunctionSwitchResult switchResult = WBUserBenefitFunctionSwitchResultOpenSuccess;
    WBUserBenefitFunctionSwitchResult (^evaluateVipEligibility)(void) = ^WBUserBenefitFunctionSwitchResult{
        if (!WBSettingManager.sharedManager.IsVIP) {    // 非会员
            return WBUserBenefitFunctionSwitchResultOpenErrorNotVip;
        } else if ((self.currentBenefit & function) == 0) { // 会员，但不包含此权益
            return WBUserBenefitFunctionSwitchResultOpenErrorVipNotHas;
        } else if ((self.currentBenefitSupport & function) == 0) {  // 会员，但不支持此权益
            return WBUserBenefitFunctionSwitchResultOpenErrorVipNotSupport;
        }
        return WBUserBenefitFunctionSwitchResultOpenSuccess;
    };

    if (!target) {  // 关闭功能
        switchResult = WBUserBenefitFunctionSwitchResultCloseSuccess;
    } else {
        if (WBSettingManager.sharedManager.BenefitTrialProperties.count > 0) {
            NSDictionary *matchedDict = nil;
            for (NSDictionary *dict in WBSettingManager.sharedManager.BenefitTrialProperties) {
                NSInteger bit = [dict[@"benefitBit"] integerValue];
                if (bit == (NSInteger)function) {
                    matchedDict = dict;
                    break;
                }
            }
            if (matchedDict) {
                id trialTimesObj = matchedDict[@"trialTimes"];
                if (trialTimesObj && trialTimesObj != [NSNull null]) {
                    NSInteger times = [WBSettingManager.sharedManager trialUsageTimesForBenefitBit:(NSInteger)function];
                    if (times <= 0) {
                        switchResult = evaluateVipEligibility();
                    }
                } else {
                    id descObj = matchedDict[@"desc"];
                    if (!descObj) {
                        switchResult = evaluateVipEligibility();
                    }
                }
            } else {
                switchResult = evaluateVipEligibility();
            }
        } else {
            switchResult = evaluateVipEligibility();
        }
    }
    NSInteger vid = vapp ? vapp.vid : 0;
    [self reportOpenBenefitFunctionEventWithVapp:vid function:function result:switchResult];
    return (switchResult == WBUserBenefitFunctionSwitchResultOpenSuccess || switchResult == WBUserBenefitFunctionSwitchResultCloseSuccess);
}

