#pragma mark - Route Log File Management

- (NSArray<NSDictionary *> *)loadRouteLogFile {
    if (![NSFileManager.defaultManager fileExistsAtPath:_routeLogFilePath]) {
        return @[];
    }

    NSError *error = nil;
    NSData *data = [NSData dataWithContentsOfFile:_routeLogFilePath options:0 error:&error];
    if (error || !data) {
        NSLog(@"Failed to read route log file: %@", error);
        return @[];
    }

    NSError *jsonError = nil;
    NSArray<NSDictionary *> *logEntries = [NSJSONSerialization JSONObjectWithData:data options:0 error:&jsonError];
    if (jsonError) {
        NSLog(@"Failed to parse route log JSON: %@", jsonError);
        return @[];
    }

    if ([logEntries isKindOfClass:[NSArray class]]) {
        return logEntries;
    }

    return @[];
}

- (void)saveRouteLogFile:(NSDictionary *)routeLog {
    if (!routeLog || routeLog.count == 0) {
        return;
    }

    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        NSMutableArray<NSDictionary *> *existingLogs = [[self loadRouteLogFile] mutableCopy];
        [existingLogs addObject:routeLog];  // 添加新日志

        // 限制日志数量，避免文件过大（保留最近1000条）
        const NSUInteger maxLogCount = 1000;
        if (existingLogs.count > maxLogCount) {
            NSRange rangeToKeep = NSMakeRange(existingLogs.count - maxLogCount, maxLogCount);
            existingLogs = [[existingLogs subarrayWithRange:rangeToKeep] mutableCopy];
        }

        NSError *error = nil;
        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:existingLogs options:0 error:&error];
        if (error) {
            NSLog(@"Failed to serialize route logs: %@", error);
            return;
        }

        // 写入文件
        NSError *writeError = nil;
        BOOL success = [jsonData writeToFile:self->_routeLogFilePath options:NSDataWritingAtomic error:&writeError];

        if (!success) {
            NSLog(@"Failed to write route log file: %@", writeError);
        }
    });
}

- (void)clearRouteLogs {
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        NSError *error = nil;
        if ([NSFileManager.defaultManager fileExistsAtPath:self->_routeLogFilePath]) {
            BOOL success = [NSFileManager.defaultManager removeItemAtPath:self->_routeLogFilePath error:&error];
            if (!success) {
                NSLog(@"Failed to clear route logs: %@", error);
            }
        }
    });
}


