//
// the file system version, one by one in strict order
//
typedef enum {
    fileSystemVersionEmpty = 0,
    fileSystemVersionClassic,
    fileSystemVersionWithStorageManager,
    // put new entries here

    fileSystemVersionMAX
} FileSystemVersionType;

static FileSystemVersionType const kNewestFileSystemVersion = fileSystemVersionMAX-1;

//
// these constsants should remain stable between versions for compatibility reasons
//
static NSString * const kDocRoot = @"docRoot";
static NSString * const kTmpRoot = @"tmpRoot";
static NSString * const kCacheRoot = @"cacheRoot";

static NSString * const kInstalledVAppList = @"vappList";
static NSString * const kSearchHistoryList = @"searchHistory";
static NSString * const kCrashReportDir = @"crashReports";
static NSString * const kDeleteUncleanedVappList = @"uncleanVappList";
static NSString * const kAppGlobalConfig = @"appGlobalConfig";
static NSString * const kAIChatsSqlite = @"aiChatsSqlite";
static NSString * const kRouteLogFile = @"routeLogFile";


@interface WBStorageManager()

@property(nonatomic, strong) NSMutableDictionary<NSString *, id> * unzipResCompletionHandler;
@property(nonatomic, assign) sqlite3 *chatDatabase;
@property(nonatomic, strong) NSMutableDictionary<NSString *, NSMutableDictionary *> *resCleanupStates;

@end

@implementation WBStorageManager


#pragma mark singleton & init

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[self alloc] init];
    });
    return instance;
}


- (instancetype)init {
    self = [super init];

    // roots initialization
    _docRoot = [[NSSearchPathForDirectoriesInDomains(NSLibraryDirectory, NSUserDomainMask, YES) firstObject] stringByAppendingPathComponent:[WBUtility getCodeNameSaltedCrc32Hash:kDocRoot]];
    _tmpRoot = [NSTemporaryDirectory() stringByAppendingPathComponent:[WBUtility getCodeNameSaltedCrc32Hash:kTmpRoot]];
    _cacheRoot = [[NSSearchPathForDirectoriesInDomains(NSCachesDirectory, NSUserDomainMask, YES) firstObject] stringByAppendingPathComponent:[WBUtility getCodeNameSaltedCrc32Hash:kCacheRoot]];
    _unzipResCompletionHandler = [NSMutableDictionary dictionary];
    _resCleanupStates = [NSMutableDictionary dictionary];
    if ([NSFileManager.defaultManager fileExistsAtPath:_docRoot] == FALSE) {
        [NSFileManager.defaultManager createDirectoryAtPath:_docRoot withIntermediateDirectories:YES attributes:nil error:nil];
    }
    if ([NSFileManager.defaultManager fileExistsAtPath:_tmpRoot] == FALSE) {
        [NSFileManager.defaultManager createDirectoryAtPath:_tmpRoot withIntermediateDirectories:YES attributes:nil error:nil];
    }
    if ([NSFileManager.defaultManager fileExistsAtPath:_cacheRoot] == FALSE) {
        [NSFileManager.defaultManager createDirectoryAtPath:_cacheRoot withIntermediateDirectories:YES attributes:nil error:nil];
    }

    _installedVAppListFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kInstalledVAppList]];
    _searchHistoryFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kSearchHistoryList]];
    _crashReportDirPath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kCrashReportDir]];
    _deleteUncleanedVAppListFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kDeleteUncleanedVappList]];
    _appConfigFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kAppGlobalConfig]];
    _routeLogFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kRouteLogFile]];
    BOOL isCrashReportDirExist = false;
    [[NSFileManager defaultManager] fileExistsAtPath:_crashReportDirPath isDirectory:&isCrashReportDirExist];
    if (!isCrashReportDirExist) {
        [NSFileManager.defaultManager createDirectoryAtPath:_crashReportDirPath withIntermediateDirectories:YES attributes:nil error:nil];
    }
    _crashReportFilePath = [_crashReportDirPath stringByAppendingPathComponent:@"crash.log"];
    [self initializeChatDatabase];
    return self;
}

- (void)initializeChatDatabase {
    _databaseQueue = dispatch_queue_create("com.webox.sqlite.queue", DISPATCH_QUEUE_SERIAL);

    dispatch_sync(_databaseQueue, ^{
        _chatDBPath = [self.docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kAIChatsSqlite]];

        if (sqlite3_open(self.chatDBPath.UTF8String, &_chatDatabase) != SQLITE_OK) {
            NSLog(@"Failed to open chat database");
            return;
        }

        // 创建会话表
        const char *createSessionTableSQL = "CREATE TABLE IF NOT EXISTS sessions ("
                                            "id TEXT PRIMARY KEY,"
                                            "agent_name TEXT NOT NULL,"
                                            "created_at DATETIME DEFAULT CURRENT_TIMESTAMP,"
                                            "latest_message TEXT);";

        // 创建消息表
        const char *createMessageTableSQL = "CREATE TABLE IF NOT EXISTS messages ("
                                            "id TEXT PRIMARY KEY,"
                                            "session_id TEXT NOT NULL,"
                                            "content TEXT NOT NULL,"
                                            "is_sender BOOLEAN NOT NULL,"
                                            "timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,"
                                            "done BOOLEAN DEFAULT 0,"
                                            "context TEXT,"
                                            "FOREIGN KEY(session_id) REFERENCES sessions(id) ON DELETE CASCADE);";

        char *errorMsg;
        if (sqlite3_exec(_chatDatabase, createSessionTableSQL, NULL, NULL, &errorMsg) != SQLITE_OK) {
            NSLog(@"Failed to create sessions table: %s", errorMsg);
            sqlite3_free(errorMsg);
        }

        if (sqlite3_exec(_chatDatabase, createMessageTableSQL, NULL, NULL, &errorMsg) != SQLITE_OK) {
            NSLog(@"Failed to create messages table: %s", errorMsg);
            sqlite3_free(errorMsg);
        }

        // 启用外键支持
        sqlite3_exec(_chatDatabase, "PRAGMA foreign_keys = ON;", NULL, NULL, NULL);
    });
}

- (void)dealloc {
    if (_chatDatabase) {
        sqlite3_close(_chatDatabase);
        _chatDatabase = nil;
    }
}


#pragma mark - file system version & migration
//
// migrate old app data to new app data, run it in a non-main thread if the migration might take a long time in the future
//
- (void)fileSystemVersionCheck {
    NSInteger currentVersion = WBSettingManager.sharedManager.FileSystemVersion;
    if (currentVersion == fileSystemVersionEmpty) {
        // its a fresh installation OR its an old filesystem with no filesystem version number
        //
        // we identify old filesystem by the existense of file "wb_vapp_status.plist"
        NSString *oldInstalledVAppListFilePath = [NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES).firstObject stringByAppendingPathComponent:@"wb_vapp_status.plist"];
        if ([NSFileManager.defaultManager fileExistsAtPath:oldInstalledVAppListFilePath]) {
            currentVersion = fileSystemVersionClassic;
        }
    }
    if (currentVersion != kNewestFileSystemVersion) {
        [self migrateFrom:currentVersion to:kNewestFileSystemVersion];
        WBSettingManager.sharedManager.FileSystemVersion = kNewestFileSystemVersion;
    }
}


- (void)migrateFrom:(NSInteger)from to:(NSInteger)to{
    while(from != to) {
        switch(from) {
            case fileSystemVersionEmpty:
                return;
            case fileSystemVersionClassic:
                from = [self migrateFromClassicToStorageManager];
            case fileSystemVersionWithStorageManager:
                return;
            default:
                NSAssert(false, @"invalid file system version");
                return;
        }
    }
}
- (NSInteger)migrateFromClassicToStorageManager {
    //
    // wb_vapp_status.plist
    //
    NSString *oldInstalledVAppListFilePath = [NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES).firstObject stringByAppendingPathComponent:@"wb_vapp_status.plist"];
    NSArray *jsonArray = [NSArray arrayWithContentsOfFile:oldInstalledVAppListFilePath];
    NSMutableArray *newJsonArray = [[NSMutableArray alloc] init];
    for(NSDictionary* dic in jsonArray) {
        NSMutableDictionary *newObj = [[NSMutableDictionary alloc] init];
        newObj[@"vid"] = dic[@"id"];
        newObj[@"name"] = dic[@"name"];
        newObj[@"trackId"] = nil;
        newObj[@"bundleId"] = dic[@"bundle_id"];
        newObj[@"iconURL"] = dic[@"icon_url"];
        newObj[@"subtitle"] = nil;
        newObj[@"artistName"] = nil;
        newObj[@"reserveCount"] = dic[@"reserve_count"];
        newObj[@"reserved"] = dic[@"reserved"];
        newObj[@"dual"] = dic[@"dual"];
        newObj[@"isDownload"] = dic[@"isDownload"];
        newObj[@"status"] = dic[@"status"];
        if ([newObj[@"status"] isKindOfClass:[NSNumber class]]) {
            if ([newObj[@"status"] intValue] == 256 || [newObj[@"status"] intValue] == 1024) {
                newObj[@"progress"] = @(1.0);
            }
        }

        NSMutableDictionary *versionObj = [[NSMutableDictionary alloc] init];
        versionObj[@"version"] = dic[@"version"];
        versionObj[@"forceUpdate"] = dic[@"force_update"];
        versionObj[@"desc"] = dic[@"description"];
        versionObj[@"refURL"] = dic[@"ref_url"];
        versionObj[@"ipaURL"] = dic[@"ipa_url"];
        versionObj[@"resURL"] = dic[@"res_url"];
        versionObj[@"ipaSize"] = dic[@"ipa_size"];
        versionObj[@"ipaHash"] = dic[@"ipa_hash"];
        versionObj[@"timeInit"] = dic[@"time_init"];
        versionObj[@"timeLaunch"] = dic[@"time_launch"];
        versionObj[@"ef"] = dic[@"ef"];
        newObj[@"versionInfo"] = versionObj;

        NSMutableDictionary *userObj = [[NSMutableDictionary alloc] init];
        userObj[@"user"] = dic[@"user"];
        userObj[@"password"] = dic[@"password"];
        userObj[@"customName"] = dic[@"fakeName"];
        userObj[@"customIcon"] = dic[@"fakeIcon"];
        newObj[@"userInfo"] = userObj;

        [newJsonArray addObject:newObj];
    }
    [newJsonArray writeToFile:_installedVAppListFilePath atomically:YES];
    [NSFileManager.defaultManager removeItemAtPath:oldInstalledVAppListFilePath error:nil];
    NSLog(@"wb_vapp_status.plist migrated");

    //
    // token in userdefaults
    //
    NSString *tokenKey = [[NSString alloc] initWithFormat:@"_%@_Token", ABBridge_GetAppCodeName()];
    NSString *token = [[NSUserDefaults standardUserDefaults] stringForKey:tokenKey];
    if (token) {
        WBSettingManager.sharedManager.Token = token;
        [[NSUserDefaults standardUserDefaults] setObject:nil forKey:tokenKey];
        NSLog(@"token migrated");
    }

    //
    // uuid in userdefaults
    //
    NSString *uuidKey = [[NSString alloc] initWithFormat:@"_%@_uuid", ABBridge_GetAppCodeName()];
    NSString *uuid = [[NSUserDefaults standardUserDefaults] stringForKey:uuidKey];
    if (uuid) {
        WBSettingManager.sharedManager.UUID = uuid;
        [[NSUserDefaults standardUserDefaults] setObject:nil forKey:uuid];
        NSLog(@"uuid migrated");
    }

    //
    // app global config
    //
    NSString *oldPasswordPath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kAppGlobalConfig]];
    if ([NSFileManager.defaultManager fileExistsAtPath:oldPasswordPath]) {
        NSString *oldPassword = [NSString stringWithContentsOfFile:oldPasswordPath encoding:NSUTF8StringEncoding error:nil];
        NSDictionary *config = @{
            @"globalPassword": oldPassword ?: @"1234"
        };
        [[WBStorageManager sharedManager] saveAppConfig:config];
        [NSFileManager.defaultManager removeItemAtPath:oldPasswordPath error:nil];
    }


    NSLog(@"migrate from classic to storagemanager complete");
    return fileSystemVersionWithStorageManager;
}


#pragma mark public API

- (NSString*)getUnzipTmpPath:(NSString *)zipFileName {
    return [_tmpRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:zipFileName]];
}

- (NSString *)getResCachePath:(WBVAppModel *)vapp {
    return [_cacheRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:[vapp.bundleId stringByAppendingString:vapp.versionInfo.resHash]]];
}

- (NSString *)getUnzipResTmpPath:(WBVAppModel *)vapp {
    return [_tmpRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:[vapp.bundleId stringByAppendingString:vapp.versionInfo.resHash]]];
}

+ (void)ensureResTmpPathReadyForVapp:(WBVAppModel *)vapp completion:(void (^)(NSString *dest, NSError * _Nullable error))completion {
    NSString *dest = [WBStorageManager.sharedManager getUnzipResTmpPath:vapp];
    BOOL isDir = NO;
    BOOL exists = [NSFileManager.defaultManager fileExistsAtPath:dest isDirectory:&isDir];
    if (exists && isDir) {
        if (completion) completion(dest, nil);
        return;
    }
    NSString *zipPath = [WBStorageManager.sharedManager getResCachePath:vapp];
    if (![NSFileManager.defaultManager fileExistsAtPath:zipPath]) {
        if (completion) completion(dest, [NSError errorWithDomain:NSCocoaErrorDomain code:4 userInfo:@{NSLocalizedDescriptionKey: @"res zip missing"}]);
        return;
    }
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        [NSFileManager.defaultManager removeItemAtPath:dest error:nil];
        BOOL ok = [SSZipArchive unzipFileAtPath:zipPath toDestination:dest];
        dispatch_async(dispatch_get_main_queue(), ^{
            if (!ok) {
                if (completion) completion(dest, [NSError errorWithDomain:NSCocoaErrorDomain code:5 userInfo:@{NSLocalizedDescriptionKey: @"res unzip failed"}]);
                return;
            }
            vapp.userInfo.resUnzipPath = dest;
            [WBStorageManager.sharedManager markResUnzipCompletedAtPath:dest];
            if (completion) completion(dest, nil);
            [WBUtility calculateSHA1ForFolder:dest includeSubdirectories:YES completion:^(NSString * _Nonnull sha1, NSError * _Nonnull error) {
                NSDictionary *data = @{ @"usingResHash": sha1 ?: error.description };
                [WBEventManager logVappUsingResHashRecord:data];
                if (!error) {
                    [WBStorageManager.sharedManager markResSHA1CompletedAtPath:dest];
                }
            }];
        });
    });
 }

- (BOOL)saveResumableData:(NSData*)data forURL:(NSString *)url {
    NSString *path = [_cacheRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:url]];
    return [data writeToFile:path atomically:YES];
}

- (NSData*)loadResumableDataForURL:(NSString *)url {
    NSString *path = [_cacheRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:url]];
    if ([NSFileManager.defaultManager fileExistsAtPath:path]) {
        return [NSData dataWithContentsOfFile:path];
    }
    return nil;
