- (NSMutableDictionary *)stateForPath:(NSString *)path createIfNeeded:(BOOL)create {
    if (path.length == 0) return nil;
    NSMutableDictionary *state = self.resCleanupStates[path];
    if (!state && create) {
        state = [@{ @"unzipDone": @NO, @"sha1Done": @NO, @"cleanupRequested": @NO } mutableCopy];
        self.resCleanupStates[path] = state;
    }
    return state;
}

- (void)markResUnzipCompletedAtPath:(NSString *)path {
    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
    if (!state) return;
    state[@"unzipDone"] = @YES;
    [self tryPerformResCleanupAtPath:path];
}

- (void)markResSHA1CompletedAtPath:(NSString *)path {
    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
    if (!state) return;
    state[@"sha1Done"] = @YES;
    [self tryPerformResCleanupAtPath:path];
}

- (void)requestResCleanupAtPath:(NSString *)path {
    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
    if (!state) return;
    state[@"cleanupRequested"] = @YES;
}

- (void)tryPerformResCleanupAtPath:(NSString *)path {
    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:NO];
    if (!state) return;
    BOOL cleanupRequested = [state[@"cleanupRequested"] boolValue];
    BOOL unzipDone = [state[@"unzipDone"] boolValue];
    BOOL sha1Done = [state[@"sha1Done"] boolValue];
    if (cleanupRequested && unzipDone && sha1Done) {
        NSFileManager *fileManager = [NSFileManager defaultManager];
        NSError *error = nil;
        if ([fileManager fileExistsAtPath:path]) {
            [fileManager removeItemAtPath:path error:&error];
        }
        [self.resCleanupStates removeObjectForKey:path];
    }
}

- (void)cleanUpResTmpPath:(NSString *)tmpPath {
    [self requestResCleanupAtPath:tmpPath];
    [self tryPerformResCleanupAtPath:tmpPath];
}

- (void)addUnzipResCompletionHandler:(void (^)(NSString * _Nullable dest))completionHandler toVApp:(WBVAppModel *)vapp {
    self.unzipResCompletionHandler[vapp.bundleId] = completionHandler;
}

