            [[WBVAppManager sharedManager] saveDeleteUncleanedAppPaths];
            break;
        }
    }
    vapp.userInfo.ipaZipPath = [_cacheRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:vapp.bundleId]];
    vapp.userInfo.resZipPath = [self getResCachePath:vapp];
}


