- (BOOL)saveSession:(WBSubAgentSession *)session {
    const char *insertSQL = "INSERT OR REPLACE INTO sessions (id, agent_name) VALUES (?, ?);";
    sqlite3_stmt *stmt;

    if (sqlite3_prepare_v2(_chatDatabase, insertSQL, -1, &stmt, NULL) == SQLITE_OK) {
        sqlite3_bind_text(stmt, 1, [session.sessionId UTF8String], -1, SQLITE_TRANSIENT);
        sqlite3_bind_text(stmt, 2, [session.agentName UTF8String], -1, SQLITE_TRANSIENT);

        if (sqlite3_step(stmt) == SQLITE_DONE) {
            sqlite3_finalize(stmt);
            return YES;
        }
    }

    sqlite3_finalize(stmt);
    return NO;
}

