@interface WBVAppResDownloadManager() <NSURLSessionDownloadDelegate>

@property(strong, nonatomic) NSMutableDictionary<NSString *, id> *downloadCompletionHandler;

@property(weak, nonatomic) NSURLSessionDownloadTask *downloadTask;
@property(strong, nonatomic) NSURLSession *session;
@property(assign, nonatomic) CFAbsoluteTime downloadStartTime;
@property(assign, nonatomic) int tryCount;
